import javax.jws.*;
import javax.xml.ws.Endpoint;
import java.util.HashMap;
import java.util.Map;

@WebService
public class EmployeeManagementService {

    private Map<Integer, Employee> employees = new HashMap<>();

    @WebMethod
    public String updateSalary(int employeeId, double newSalary) {
        Employee employee = employees.get(employeeId);
        if (employee != null) {
            employee.setSalary(newSalary);
            return "Salary updated for employee with ID: " + employeeId;
        } else {
            return "Employee not found!";
        }
    }

    @WebMethod
    public String addPerformanceReview(int employeeId, String review) {
        Employee employee = employees.get(employeeId);
        if (employee != null) {
            employee.addPerformanceReview(review);
            return "Performance review added for employee with ID: " + employeeId;
        } else {
            return "Employee not found!";
        }
    }

    @WebMethod
    public String terminateEmployee(int employeeId) {
        if (employees.remove(employeeId) != null) {
            return "Employee with ID: " + employeeId + " terminated.";
        } else {
            return "Employee not found!";
        }
    }

    @WebMethod(exclude = true)
    public void addEmployee(int employeeId, String name, double salary) {
        employees.put(employeeId, new Employee(employeeId, name, salary));
    }

    public static void main(String[] args) {
        EmployeeManagementService service = new EmployeeManagementService();
        service.addEmployee(1, "John Proctor", 75000);
        service.addEmployee(2, "Elizabeth Proctor", 80000);

        String url = "http://localhost:8080/employeemanagement";
        Endpoint.publish(url, service);
        System.out.println("Service published at " + url);
    }

    class Employee {
        private int id;
        private String name;
        private double salary;
        private String performanceReviews;

        public Employee(int id, String name, double salary) {
            this.id = id;
            this.name = name;
            this.salary = salary;
            this.performanceReviews = "";
        }

        public void setSalary(double salary) {
            this.salary = salary;
        }

        public void addPerformanceReview(String review) {
            this.performanceReviews += review + "\n";
        }
    }
}